var x = [{
        u: "/",
        ti: "༺ˇ»`全部分类´«ˇ༻",
        se: "nav.nav li:not(:nth-child(1)):not(:nth-child(9)):not(:nth-child(10)) a"

    },
    {
        u: "/paihang/",
        ti: "༺ˇ»`全部排行´«ˇ༻",
        se: "div[align='center'] a"
    }];

x.forEach(i => {
    var o = org.jsoup.Jsoup.parse(java.ajax(i.u));
    var s = o.select(i.se);
    push(i.ti, "", 1, 1);
    s.forEach((j,index) => {
        var url = String(j.attr("href")).replace(/(\d+)\/$/,"{{page}}/");
        if(index + 1 <= s.length - s.length % 3){
        push(j.text(), url, 1, 0.25)
        }else{
        	push(j.text(), url, -1, 0.29)
        	}
    })
});

JSON.stringify(sort);

