🕰  更新时间：{{@@.time span@text}}
📒  作品Tags：{{@@.category a.0@text}}
🔶  状态：{{@@.category span.2@text}}
📜  内容简介：
{{@@.BGsectionTwo-bottom@text}}##(^|[。！？……；]+[”」）】]?)##$1<br>

ruleToc.chapterList:
ol li
@js:
try {
    a = src.match(/var originalOrder = \[.*\];/)[0]
    eval(String(a))

    list = []
    for (i in result) {
        list[originalOrder[i]] = result[i]
    }

    lyu = []
    for (i in list) {
        data = String(list[i]).match(/([^\s]+-[^\s]+?)(?==")/)

        if (data) {
            lyu.push({
                text: String(list[i].attr(data[1])).trim(),
                href: list[i].attr("href")
            })
        } else {
            lyu.push({
                text: String(list[i].text()).trim(),
                href: list[i].attr("href")
            })
        }
    }

    lyu

} catch (err) {

    J = result.select("a");

    list = [];
    for (i = 0; i < J.length; ++i) {
        data = String(J[i]).match(/([^\s]+-[^\s]+?)(?==")/g)
        data1 = String(result[i]).match(/([^\s]+-[^\s]+?)(?==")/g)

        for (k = 0; k < data.length; k++) {
            if (J[i].attr(data[k]).includes("L2J")) {
                url = java.base64Decode(J[i].attr(data[k]))
            } else {
                name = J[i].attr(data[k])
            }
        }

        list.push({
            text: String(name).trim(),
            href: url,
            num: result[i].attr(data1[1])
        });
    }

    Rule = (a, b) => a.num - b.num;

    list.sort(Rule);
}

