exploreUrl:
@js:
    java.toast("正在努力加载中，请稍后");
var sort = [];
var push = (title, url, type1, type2) => {
    sort.push({
        title: title,
        url: url,
        style: {
            layout_flexGrow: type1,
            layout_flexBasisPercent: type2
        }
    });
};
var sites = [{
        u: "/sort.html",
        ti: "༺ˇ»`全部分类´«ˇ༻"
    },
    {
        u: "/top.html",
        ti: "༺ˇ»`全部排行´«ˇ༻"
    }];
for (var site of sites) {
    var o = org.jsoup.Jsoup.parse(java.ajax(site.u));
    var s = o.select('.content li a');
    push(site.ti, "", "1", "1");
    for (var i = 0; i < s.size(); i++) {
        var urls = String(s[i].attr("href")).replace(/\/(.*)-(.*)-(\d+)\//, "/$1-$2-{{page}}/");
        if (s.length % 3 === 1) {
            push(s[i].text(), urls, "-1", "0.29")
        } else {
            push(s[i].text(), urls, "1", "0.25")
        }
    }
}
push("༺ˇ»`全本小说´«ˇ༻", `/full-{{page}}/`, "1", "1")
JSON.stringify(sort);

